import java.util.*;

class FoodRatings {
    private final Map<String, Integer> foodRating = new HashMap<>();
    private final Map<String, String> foodCuisine = new HashMap<>();
    private final Map<String, TreeSet<String>> cuisineTop = new HashMap<>();

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        for (int i = 0; i < foods.length; i++) {
            String food = foods[i];
            String cuisine = cuisines[i];
            int rating = ratings[i];
            foodRating.put(food, rating);
            foodCuisine.put(food, cuisine);
            cuisineTop.computeIfAbsent(cuisine, k -> new TreeSet<>(
                (a, b) -> {
                    int cmp = Integer.compare(foodRating.get(b), foodRating.get(a));
                    return cmp != 0 ? cmp : a.compareTo(b);
                })
            ).add(food);
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = foodCuisine.get(food);
        TreeSet<String> set = cuisineTop.get(cuisine);
        set.remove(food);
        foodRating.put(food, newRating);
        set.add(food);
    }

    public String highestRated(String cuisine) {
        return cuisineTop.get(cuisine).first();
    }
}
```
efficiency: HIGH
time complexity: O(log n) for changeRating and O(1) for highestRated
space complexity: O(n)
energy implications: LOW
explanation: Uses a TreeSet per cuisine to keep foods sorted by (-rating, name) so highestRated is O(1) via first(). changeRating removes and re-inserts the food to update its position in O(log n). Two auxiliary maps store current rating and cuisine for each food.

